1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	const CURSE_SURCHARGE = 0.5;
9	const FIRST_INSURANCE_SURCHARGE = 0.1;
10	
