31	const PROCESSING_FEE = 5;
32	
33	const BASE_PREMIUM: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: 25,
39	  moonstone: 25,
40	};
41	
42	const basePremiumFor = (item: Item): number => BASE_PREMIUM[item.type] ?? 0;
43	
44	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
45	const COMPONENT_BLOCK_SIZE = 3;
46	const COMPONENT_BLOCK_PRICE = 60;
47	
48	const groupByType = (items: Item[]): Map<string, Item[]> => {
49	  const groups = new Map<string, Item[]>();
50	  for (const item of items) {
51	    const group = groups.get(item.type) ?? [];
52	    group.push(item);
53	    groups.set(item.type, group);
54	  }
55	  return groups;
56	};
57	
58	const itemModifiersFor = (item: Item): number => {
59	  let factor = FIRST_INSURANCE_SURCHARGE;
60	  if (item.cursed) factor += CURSE_SURCHARGE;
61	  return basePremiumFor(item) * factor;
62	};
63	
64	const groupBaseCost = (type: string, group: Item[]): number => {
65	  if (
66	    COMPONENT_TYPES.has(type) &&
67	    group.length === COMPONENT_BLOCK_SIZE
68	  ) {
69	    return COMPONENT_BLOCK_PRICE;
70	  }
71	  return group.reduce((sum, item) => sum + basePremiumFor(item), 0);
72	};
73	
74	const itemsSubtotal = (items: Item[]): number => {
75	  let total = 0;
76	  for (const [type, group] of groupByType(items)) {
77	    total += groupBaseCost(type, group);
78	    for (const item of group) {
79	      total += itemModifiersFor(item);
80	    }
81	  }
82	  return total;
83	};
84	
85	const quote = (items: Item[]): QuoteResult => ({
86	  premium: Math.ceil(itemsSubtotal(items) + PROCESSING_FEE),
87	});
88	
89	export const runScenario = (scenario: Scenario): ScenarioResult => ({
90	  results: scenario.steps.map((step) => quote(step.items)),
91	});
